export function createHideableComponent<T, P = {}>(
  fn: (props: P, ref: React.Ref<T>) => ReactElement | null
): (props: P & React.RefAttributes<T>) => ReactElement | null {
  let Wrapper = (props: P, ref: React.Ref<T>) => {
    let isHidden = useContext(HiddenContext);
    if (isHidden) {
      return null;
    }

    return fn(props, ref);
  };
  // @ts-ignore - for react dev tools
  Wrapper.displayName = fn.displayName || fn.name;
  return (forwardRef as forwardRefType)(Wrapper);
}

onKeyUp(e: KeyboardEvent): void {
  this.cancelEvent(e);

  if (e.key === 'Enter') {
    if (e.altKey || nodeContains(this.getCurrentActivateButton(), getEventTarget(e) as Node)) {
      this.activate(this.currentDropTarget, this.currentDropItem);
    } else {
      this.drop();
    }
  }
}

function createFileItem(file: File | null): FileDropItem {
  if (!file) {
    throw new Error('No file provided');
  }
  return {
    kind: 'file',
    type: file.type || GENERIC_TYPE,
    name: file.name,
    getText: () => blobToString(file),
    getFile: () => Promise.resolve(file)
  };
}

function isValidKey(e: KeyboardEvent) {
  // Control and Shift keys trigger when navigating back to the tab with keyboard.
  return !(
    e.metaKey ||
    (!isMac() && e.altKey) ||
    e.ctrlKey ||
    e.key === 'Control' ||
    e.key === 'Shift' ||
    e.key === 'Meta'
  );
}

clear(assertiveness: Assertiveness) {
  if (!this.node) {
    return;
  }

  if ((!assertiveness || assertiveness === 'assertive') && this.assertiveLog) {
    this.assertiveLog.innerHTML = '';
  }

  if ((!assertiveness || assertiveness === 'polite') && this.politeLog) {
    this.politeLog.innerHTML = '';
  }
}

function getMargins(node: Element): Position {
  let style = window.getComputedStyle(node);
  return {
    top: parseInt(style.marginTop, 10) || 0,
    bottom: parseInt(style.marginBottom, 10) || 0,
    left: parseInt(style.marginLeft, 10) || 0,
    right: parseInt(style.marginRight, 10) || 0
  };
}

export function useLinkProps(props?: LinkDOMProps): LinkDOMProps {
  let router = useRouter();
  const href = router.useHref(props?.href ?? '');
  let linkProps: LinkDOMProps = {};
  if (props) {
    for (let key of ['href', 'target', 'rel', 'download', 'ping', 'referrerPolicy']) {
      if (key in props) {
        linkProps[key] = key === 'href' ? href : props[key];
      }
    }
  }
  return linkProps;
}

export function useEffectEvent<T extends Function>(fn?: T): T {
  const ref = useRef<T | null | undefined>(null);
  useEarlyEffect(() => {
    ref.current = fn;
  }, [fn]);
  // @ts-ignore
  return useCallback<T>((...args) => {
    const f = ref.current!;
    return f?.(...args);
  }, []);
}

export function useSlotId(depArray: ReadonlyArray<any> = []): string {
  let id = useId();
  let [resolvedId, setResolvedId] = useValueEffect(id);
  let updateId = useCallback(() => {
    setResolvedId(function* () {
      yield id;

      yield document.getElementById(id) ? id : undefined;
    });
  }, [id, setResolvedId]);

  useLayoutEffect(updateId, [id, updateId, ...depArray]);

  return resolvedId;
}

export function useSyncRef<T>(context?: ContextValue<T> | null, ref?: RefObject<T | null>): void {
  useLayoutEffect(() => {
    if (context && context.ref && ref) {
      context.ref.current = ref.current;
      return () => {
        if (context.ref) {
          // oxlint-disable-next-line react-hooks/exhaustive-deps
          context.ref.current = null;
        }
      };
    }
  });
}

function getAncestors<T>(collection: Collection<Node<T>>, node: Node<T>): Node<T>[] {
  let parents: Node<T>[] = [];

  let currNode: Node<T> | null = node;
  while (currNode?.parentKey != null) {
    currNode = collection.getItem(currNode.parentKey);
    if (currNode) {
      parents.unshift(currNode);
    }
  }

  return parents;
}

function addColorValue(color: Color, step: number) {
  let newColor = color ? color : MIN_COLOR;
  let colorInt = newColor.toHexInt();

  let clampInt = Math.min(Math.max(colorInt + step, MIN_COLOR_INT), MAX_COLOR_INT);
  if (clampInt !== colorInt) {
    let newColorString = `#${clampInt.toString(16).padStart(6, '0').toUpperCase()}`;
    newColor = parseColor(newColorString);
  }
  return newColor;
}

function isEqualDropTarget(a?: DropTarget | null, b?: DropTarget | null) {
  if (!a) {
    return !b;
  }

  switch (a.type) {
    case 'root':
      return b?.type === 'root';
    case 'item':
      return b?.type === 'item' && b?.key === a.key && b?.dropPosition === a.dropPosition;
  }
}

getChildren(key: Key): Iterable<GridNode<T>> {
  if (key === this.body.key) {
    return this.body.childNodes;
  }

  let node = this.getItem(key);
  if (node?.type === 'item') {
    return [...node.childNodes].filter(n => n.type === 'cell');
  }

  return super.getChildren(key);
}

splitColumnsIntoControlledAndUncontrolled(
  columns: Array<GridNode<T>>
): [Map<Key, GridNode<T>>, Map<Key, GridNode<T>>] {
  return columns.reduce(
    (acc, col) => {
      if (col.props.width != null) {
        acc[0].set(col.key, col);
      } else {
        acc[1].set(col.key, col);
      }
      return acc;
    },
    [new Map(), new Map()]
  );
}

setVisibleRect(rect: Rect): void {
  let time = performance.now() - this.startTime;
  if (time < 500) {
    if (rect.x !== this.visibleRect.x && time > 0) {
      this.velocity.x = (rect.x - this.visibleRect.x) / time;
    }

    if (rect.y !== this.visibleRect.y && time > 0) {
      this.velocity.y = (rect.y - this.visibleRect.y) / time;
    }
  }

  this.startTime = performance.now();
  this.visibleRect = rect;
}

intersects(rect: Rect): boolean {
  let isTestEnv = process.env.NODE_ENV === 'test' && !process.env.VIRT_ON;
  return (
    (isTestEnv || (this.area > 0 && rect.area > 0)) &&
    this.x <= rect.x + rect.width &&
    rect.x <= this.x + this.width &&
    this.y <= rect.y + rect.height &&
    rect.y <= this.y + this.height
  );
}

function isNativeTabbable(tagName?: string) {
  if (!tagName) return true;
  return (
    tagName === "button" ||
    tagName === "summary" ||
    tagName === "input" ||
    tagName === "select" ||
    tagName === "textarea" ||
    tagName === "a"
  );
}

function useMenuBar(props) {
  useEffect(() => {
    if (process.env.NODE_ENV !== "production") {
      console.warn(
        "MenuBar is deprecated. Use Menubar instead.",
        "See https://ariakit.com/reference/menubar",
      );
    }
  }, []);
  return useMenubar(props);
}

function getInitialFocus(event: KeyboardEvent, dir: BasePlacement) {
  const keyMap = {
    ArrowDown: dir === "bottom" || dir === "top" ? "first" : false,
    ArrowUp: dir === "bottom" || dir === "top" ? "last" : false,
    ArrowRight: dir === "right" ? "first" : false,
    ArrowLeft: dir === "left" ? "first" : false,
  } as const;
  return keyMap[event.key as keyof typeof keyMap];
}

export function useId(defaultId?: string): string | undefined {
  if (useReactId) {
    const reactId = useReactId();
    if (defaultId) return defaultId;
    return reactId;
  }
  const [id, setId] = useState(defaultId);
  useSafeLayoutEffect(() => {
    if (defaultId || id) return;
    const random = Math.random().toString(36).slice(2, 8);
    setId(`id-${random}`);
  }, [defaultId, id]);
  return defaultId || id;
}

export function useMetadataProps<T, K extends keyof any>(
  props: { onLoadedMetadataCapture?: AnyFunction & { [key in K]?: T } },
  key: K,
  value: T,
) {
  const parent = props.onLoadedMetadataCapture;
  const onLoadedMetadataCapture = useMemo(() => {
    return Object.assign(
      () => {},
      parent,
      ...(value !== undefined ? [{ [key]: value }] : []),
    );
  }, [parent, key, value]);

  return [parent?.[key], { onLoadedMetadataCapture }] as const;
}

function hasMouseMovement(event: ReactMouseEvent | MouseEvent) {
  const movementX = event.movementX || event.screenX - previousScreenX;
  const movementY = event.movementY || event.screenY - previousScreenY;
  previousScreenX = event.screenX;
  previousScreenY = event.screenY;
  return movementX || movementY || process.env.NODE_ENV === "test";
}

(props: ClientOnlyProps): React.ReactNode => {
  const { children, fallback } = props

  const isClient = useSyncExternalStore(
    () => noop,
    () => true,
    () => false,
  )

  if (!isClient) {
    return fallback
  }

  return <>{typeof children === 'function' ? children() : children}</>
}

(props, ref) => {
  const colorPicker = useColorPickerContext()
  const mergedProps = mergeProps(colorPicker.getFormatSelectProps(), props)

  return (
    <ark.select {...mergedProps} ref={ref}>
      {['rgba', 'hsla', 'hsba'].map((format) => (
        <ark.option key={format} value={format}>
          {format}
        </ark.option>
      ))}
    </ark.select>
  )
}

(props, ref) => {
  const id = useId()
  const [_itemGroupProps, localProps] = splitItemGroupProps(props, ['id'])
  const itemGroupProps = { id, ..._itemGroupProps }

  const combobox = useComboboxContext()
  const mergedProps = mergeProps(combobox.getItemGroupProps(itemGroupProps), localProps)

  return (
    <ComboboxItemGroupPropsProvider value={itemGroupProps}>
      <ark.div {...mergedProps} ref={ref} />
    </ComboboxItemGroupPropsProvider>
  )
}

(props, ref) => {
